/**
 * Sets the x and y-coordinates of the bottom left corner from vector
 * @param position The position vector
 * @return this rectangle for chaining
 */
public Rectangle setPosition(Vector2 position) {
    this.x = position.x;
    this.y = position.y;
    return this;
}
